class Solution {
    public boolean canChange(String start, String target) {
        int n = start.length();
        int startL = 0, startR = 0, targetL = 0, targetR = 0;
        for (int i = 0; i < n; i++) {
            if (start.charAt(i) == 'L') startL++;
            if (start.charAt(i) == 'R') startR++;
            if (target.charAt(i) == 'L') targetL++;
            if (target.charAt(i) == 'R') targetR++;
        }
        if (startL != targetL || startR != targetR) return false;
        int startIdx = 0, targetIdx = 0;
        while (startIdx < n && targetIdx < n) {
            while (startIdx < n && start.charAt(startIdx) == '_') startIdx++;
            while (targetIdx < n && target.charAt(targetIdx) == '_') targetIdx++;
            if (startIdx == n && targetIdx == n) return true;
            if (startIdx == n || targetIdx == n) return false;
            if (start.charAt(startIdx) != target.charAt(targetIdx)) return false;
            if (start.charAt(startIdx) == 'L' && startIdx < targetIdx) return false;
            if (start.charAt(startIdx) == 'R' && startIdx > targetIdx) return false;
            startIdx++;
            targetIdx++;
        }
        return true;
    }
}
